import { useRef, useState } from 'react'
import type { NavFloor } from '@shared/types'

/* ──────────────── Props ──────────────── */

interface ManageFloorsModalProps {
  isOpen: boolean
  buildingId: number
  floors: NavFloor[]
  onClose: () => void
  onFloorAdded: (floor: NavFloor) => void
  onFloorDeleted: (floorId: number) => void
  onFloorImageReplaced: () => void
}

/* ──────────────── Component ──────────────── */

export default function ManageFloorsModal({
  isOpen,
  buildingId,
  floors,
  onClose,
  onFloorAdded,
  onFloorDeleted,
  onFloorImageReplaced,
}: ManageFloorsModalProps) {
  const [isSaving, setIsSaving] = useState(false)
  const [newFloorNumber, setNewFloorNumber] = useState<string>('')
  const [newFloorFile, setNewFloorFile] = useState<File | null>(null)
  const newFloorFileInputRef = useRef<HTMLInputElement>(null)

  // Per-row replace-image file inputs (keyed by floor.id)
  const replaceInputRefs = useRef<Map<number, HTMLInputElement>>(new Map())

  if (!isOpen) return null

  const sortedFloors = [...floors].sort((a, b) => a.floorNumber - b.floorNumber)

  async function handleReplaceImage(floor: NavFloor, file: File) {
    setIsSaving(true)
    try {
      const formData = new FormData()
      formData.append('image', file)
      await fetch(`/api/admin/floor-plan/${buildingId}/${floor.floorNumber}`, {
        method: 'POST',
        credentials: 'include',
        body: formData,
      })
      onFloorImageReplaced()
    } finally {
      setIsSaving(false)
    }
  }

  async function handleDeleteFloor(floor: NavFloor) {
    if (floor.nodes.length > 0) {
      const confirmed = window.confirm(
        `Floor ${floor.floorNumber} has ${floor.nodes.length} nodes. Delete all?`,
      )
      if (!confirmed) return
    }
    setIsSaving(true)
    try {
      await fetch(`/api/admin/floors/${floor.id}`, {
        method: 'DELETE',
        credentials: 'include',
      })
      onFloorDeleted(floor.id)
    } finally {
      setIsSaving(false)
    }
  }

  async function handleAddFloor(e: React.FormEvent) {
    e.preventDefault()
    if (!newFloorFile || !newFloorNumber) return
    setIsSaving(true)
    try {
      const formData = new FormData()
      formData.append('buildingId', String(buildingId))
      formData.append('floorNumber', newFloorNumber)
      formData.append('image', newFloorFile)
      const res = await fetch('/api/admin/floors', {
        method: 'POST',
        credentials: 'include',
        body: formData,
      })
      const { floorId } = await res.json() as { ok: boolean; floorId: number }
      const ext = newFloorFile.name.split('.').pop()?.toLowerCase() ?? 'png'
      const newFloor: NavFloor = {
        id: floorId,
        floorNumber: Number(newFloorNumber),
        imagePath: `floor-plan-${buildingId}-${newFloorNumber}.${ext}`,
        updatedAt: new Date().toISOString(),
        nodes: [],
        edges: [],
      }
      setNewFloorNumber('')
      setNewFloorFile(null)
      if (newFloorFileInputRef.current) {
        newFloorFileInputRef.current.value = ''
      }
      onFloorAdded(newFloor)
    } finally {
      setIsSaving(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
      <div className="bg-white rounded-lg shadow-xl w-[480px] max-h-[80vh] flex flex-col">
        {/* Header */}
        <div className="flex items-center justify-between px-5 py-4 border-b">
          <h2 className="text-base font-semibold text-gray-800">Manage Floors</h2>
          <button
            type="button"
            onClick={onClose}
            className="text-gray-500 hover:text-gray-800 text-xl leading-none focus:outline-none"
            aria-label="Close"
          >
            &times;
          </button>
        </div>

        {/* Floor list */}
        <div className="overflow-y-auto flex-1 px-5 py-3 flex flex-col gap-2">
          {sortedFloors.length === 0 && (
            <p className="text-sm text-gray-500 py-2">No floors yet. Add one below.</p>
          )}
          {sortedFloors.map((floor) => (
            <div
              key={floor.id}
              className="flex items-center gap-3 py-2 border-b border-gray-100 last:border-b-0"
            >
              {/* Floor label */}
              <span className="text-sm font-medium text-gray-700 w-20 shrink-0">
                Floor {floor.floorNumber}
              </span>

              {/* Image preview */}
              <img
                src={`/api/floor-plan/${buildingId}/${floor.floorNumber}`}
                alt={`Floor ${floor.floorNumber} plan`}
                className="w-12 h-8 object-cover rounded border border-gray-200"
              />

              <div className="flex-1" />

              {/* Replace Image */}
              <input
                ref={(el) => {
                  if (el) replaceInputRefs.current.set(floor.id, el)
                  else replaceInputRefs.current.delete(floor.id)
                }}
                type="file"
                accept="image/*"
                className="hidden"
                onChange={(e) => {
                  const file = e.target.files?.[0]
                  if (file) handleReplaceImage(floor, file)
                }}
              />
              <button
                type="button"
                disabled={isSaving}
                onClick={() => replaceInputRefs.current.get(floor.id)?.click()}
                className="text-xs px-2 py-1 rounded border border-gray-300 text-gray-700 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Replace Image
              </button>

              {/* Delete */}
              <button
                type="button"
                disabled={isSaving}
                onClick={() => handleDeleteFloor(floor)}
                className="text-xs px-2 py-1 rounded border border-red-300 text-red-600 hover:bg-red-50 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Delete
              </button>
            </div>
          ))}
        </div>

        {/* Add Floor form */}
        <form
          onSubmit={handleAddFloor}
          className="border-t px-5 py-4 flex flex-col gap-3 bg-gray-50"
        >
          <p className="text-xs font-semibold text-gray-600 uppercase tracking-wide">Add Floor</p>
          <div className="flex items-center gap-3">
            <input
              type="number"
              min={1}
              step={1}
              placeholder="Floor #"
              value={newFloorNumber}
              onChange={(e) => setNewFloorNumber(e.target.value)}
              className="w-24 border rounded px-2 py-1.5 text-sm focus:outline-none focus:ring-1 focus:ring-blue-500"
            />
            <input
              ref={newFloorFileInputRef}
              type="file"
              accept="image/*"
              className="text-sm text-gray-600 file:mr-2 file:py-1 file:px-2 file:rounded file:border file:border-gray-300 file:text-sm file:bg-white file:text-gray-700 hover:file:bg-gray-50"
              onChange={(e) => setNewFloorFile(e.target.files?.[0] ?? null)}
            />
          </div>
          <button
            type="submit"
            disabled={!newFloorNumber || !newFloorFile || isSaving}
            className="self-start px-4 py-1.5 rounded bg-blue-600 text-white text-sm font-medium hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            Add Floor
          </button>
        </form>
      </div>
    </div>
  )
}

import type { EditorMode } from '../../hooks/useEditorState'

/* ──────────────── Props ──────────────── */

interface EditorToolbarProps {
  mode: EditorMode
  onModeChange: (mode: EditorMode) => void
  onUpload: () => void
  onSave: () => void
  onUndo: () => void
  onRedo: () => void
  canUndo: boolean
  canRedo: boolean
  isDirty: boolean
  onLogout: () => void
  onManageFloors?: () => void
  isCampusActive?: boolean
}

/* ──────────────── Component ──────────────── */

export default function EditorToolbar({
  mode,
  onModeChange,
  onUpload,
  onSave,
  onUndo,
  onRedo,
  canUndo,
  canRedo,
  isDirty,
  onLogout,
  onManageFloors,
  isCampusActive,
}: EditorToolbarProps) {
  const modeButtonClass = (m: EditorMode) =>
    m === mode
      ? 'bg-blue-600 text-white border border-blue-600 px-3 py-1 rounded text-sm font-medium'
      : 'bg-white text-gray-700 border border-gray-300 px-3 py-1 rounded text-sm font-medium hover:bg-gray-50'

  const disabledClass = 'opacity-50 cursor-not-allowed'

  return (
    <div className="relative w-full z-10 bg-white border-b shadow-sm px-4 py-2 flex items-center gap-2 flex-wrap">
      {/* Mode buttons */}
      <div className="flex items-center gap-1">
        <button
          type="button"
          className={modeButtonClass('select')}
          onClick={() => onModeChange('select')}
        >
          Select
        </button>
        <button
          type="button"
          className={modeButtonClass('add-node')}
          onClick={() => onModeChange('add-node')}
        >
          Add Node
        </button>
        <button
          type="button"
          className={modeButtonClass('add-edge')}
          onClick={() => onModeChange('add-edge')}
        >
          Add Edge
        </button>
      </div>

      {/* Separator */}
      <div className="h-6 w-px bg-gray-200 mx-1" />

      {/* Upload and Save */}
      <div className="flex items-center gap-2">
        <button
          type="button"
          className="bg-white text-gray-700 border border-gray-300 px-3 py-1 rounded text-sm font-medium hover:bg-gray-50"
          onClick={onUpload}
        >
          {isCampusActive ? 'Upload Campus Map' : 'Upload Floor Plan'}
        </button>
        {!isCampusActive && onManageFloors && (
          <button
            type="button"
            className="bg-white text-gray-700 border border-gray-300 px-3 py-1 rounded text-sm font-medium hover:bg-gray-50"
            onClick={onManageFloors}
          >
            Manage Floors
          </button>
        )}
        <button
          type="button"
          className={`px-3 py-1 rounded text-sm font-medium border ${
            isDirty
              ? 'bg-green-600 text-white border-green-600 hover:bg-green-700'
              : 'bg-gray-100 text-gray-400 border-gray-200'
          }`}
          onClick={onSave}
        >
          Save
        </button>
      </div>

      {/* Separator */}
      <div className="h-6 w-px bg-gray-200 mx-1" />

      {/* Undo / Redo */}
      <div className="flex items-center gap-1">
        <button
          type="button"
          className={`bg-white text-gray-700 border border-gray-300 px-3 py-1 rounded text-sm font-medium hover:bg-gray-50 ${!canUndo ? disabledClass : ''}`}
          onClick={onUndo}
          disabled={!canUndo}
        >
          Undo
        </button>
        <button
          type="button"
          className={`bg-white text-gray-700 border border-gray-300 px-3 py-1 rounded text-sm font-medium hover:bg-gray-50 ${!canRedo ? disabledClass : ''}`}
          onClick={onRedo}
          disabled={!canRedo}
        >
          Redo
        </button>
      </div>

      {/* Spacer to push logout to the right */}
      <div className="flex-1" />

      {/* Logout */}
      <button
        type="button"
        className="bg-red-500 text-white px-3 py-1 rounded text-sm font-medium hover:bg-red-600"
        onClick={onLogout}
      >
        Logout
      </button>
    </div>
  )
}

import type { NavBuilding, NavEdge, NavFloor, NavGraph, NavNode } from '@shared/types'
import type Konva from 'konva'
import { useCallback, useEffect, useMemo, useRef, useState } from 'react'
import { Layer, Stage } from 'react-konva'
import useImage from 'use-image'
import { DataTabToolbar } from '../../components/admin/DataTabToolbar'
import { EdgeDataTable } from '../../components/admin/EdgeDataTable'
import EdgeLayer from '../../components/admin/EdgeLayer'
import EditorSidePanel from '../../components/admin/EditorSidePanel'
import EditorToolbar from '../../components/admin/EditorToolbar'
import ManageFloorsModal from '../../components/admin/ManageFloorsModal'
import { NodeDataTable } from '../../components/admin/NodeDataTable'
import NodeMarkerLayer from '../../components/admin/NodeMarkerLayer'
import {
  applyConnectorUpdatesToFloorNodes,
  applyConnectorUpdatesToNavGraph,
  deriveConnectorCandidates,
  isConnectorNodeType,
  type ConnectorDirection,
  type ConnectorUpdatedNode,
} from '../../components/admin/connectorLinking'
import FloorPlanImage from '../../components/FloorPlanImage'
import {
  calcDistance,
  generateEdgeId,
  generateNodeId,
  useEditorState,
} from '../../hooks/useEditorState'
import { useMapViewport } from '../../hooks/useMapViewport'

/* ──────────────── Props ──────────────── */

interface MapEditorCanvasProps {
  onLogout: () => void
}

interface ConnectorLinkSuccessResponse {
  ok: true
  updatedNodes: ConnectorUpdatedNode[]
}

interface ConnectorLinkErrorResponse {
  errorCode?: string
  error?: string
}

/* ──────────────── Component ──────────────── */

export default function MapEditorCanvas({ onLogout }: MapEditorCanvasProps) {
  const { state, dispatch, recordHistory, handleUndo, handleRedo, canUndo, canRedo, switchFloor, switchToCampus } =
    useEditorState()

  const stageRef = useRef<Konva.Stage>(null)
  const floorPlanLayerRef = useRef<Konva.Layer>(null)
  const fileInputRef = useRef<HTMLInputElement>(null)
  const canvasContainerRef = useRef<HTMLDivElement>(null)
  const [canvasSize, setCanvasSize] = useState({ width: 0, height: 0 })

  useEffect(() => {
    const el = canvasContainerRef.current
    if (!el) return
    const ro = new ResizeObserver((entries) => {
      const entry = entries[0]
      if (!entry) return
      const { width, height } = entry.contentRect
      setCanvasSize({ width, height })
    })
    ro.observe(el)
    return () => ro.disconnect()
  }, [])

  const [activeTab, setActiveTab] = useState<'map' | 'data'>('map')
  const [activeSubTab, setActiveSubTab] = useState<'nodes' | 'edges'>('nodes')

  const [imageRect, setImageRect] = useState<{
    x: number
    y: number
    width: number
    height: number
  } | null>(null)
  const [stageScale, setStageScale] = useState<number>(1)
  const [floorPlanUrl, setFloorPlanUrl] = useState<string>('/api/floor-plan/image')
  const [cursorCanvasPos, setCursorCanvasPos] = useState<{ x: number; y: number } | null>(null)

  // Multi-floor state
  const [navGraph, setNavGraph] = useState<NavGraph | null>(null)
  const [manageFloorsOpen, setManageFloorsOpen] = useState(false)
  const [isSavingFloor, setIsSavingFloor] = useState(false)
  const [connectorLinkError, setConnectorLinkError] = useState<string | null>(null)
  const [isConnectorLinkPending, setIsConnectorLinkPending] = useState(false)

  const canvasWidth = canvasSize.width
  const canvasHeight = canvasSize.height

  // Load floor plan image via use-image
  const [image, imageStatus] = useImage(floorPlanUrl)
  const isFullLoaded = imageStatus === 'loaded'

  const { handleWheel, handleTouchMove, handleTouchEnd, handleDragEnd } = useMapViewport({
    stageRef,
    imageRect,
    onScaleChange: setStageScale,
  })

  // Load graph from server on mount — initialize multi-floor NavGraph state
  // Note: uses dispatch directly (not switchFloor) so this callback stays stable.
  // switchFloor is not useCallback-wrapped, so including it as a dep would cause
  // loadNavGraph to rebuild every render → infinite useEffect loop.
  const loadNavGraph = useCallback(async () => {
    try {
      const res = await fetch('/api/map', { credentials: 'include' })
      if (!res.ok) return
      const graph = (await res.json()) as NavGraph
      setNavGraph(graph)
      // Auto-select first real building (non-Campus), first floor
      const firstRealBuilding = graph.buildings.find((b) => b.name !== 'Campus')
      if (firstRealBuilding) {
        const firstFloor = firstRealBuilding.floors.slice().sort((a, b) => a.floorNumber - b.floorNumber)[0]
        if (firstFloor) {
          dispatch({ type: 'SWITCH_BUILDING', buildingId: firstRealBuilding.id })
          dispatch({ type: 'SWITCH_FLOOR', floorId: firstFloor.id, nodes: firstFloor.nodes, edges: firstFloor.edges })
          setFloorPlanUrl(`/api/floor-plan/${firstRealBuilding.id}/${firstFloor.floorNumber}?t=${firstFloor.updatedAt}`)
        }
      }
    } catch {
      // Silently fail — editor starts empty if graph cannot be loaded
    }
  }, [dispatch])

  useEffect(() => {
    loadNavGraph()
  }, [loadNavGraph])

  // Derived helpers from navGraph + state
  const isCampusActive = state.activeBuildingId === 'campus'

  const nonCampusBuildings: NavBuilding[] = (navGraph?.buildings ?? []).filter((b) => b.name !== 'Campus')

  const activeBuilding: NavBuilding | undefined = isCampusActive
    ? undefined
    : nonCampusBuildings.find((b) => b.id === state.activeBuildingId)

  const sortedFloors: NavFloor[] = (activeBuilding?.floors ?? [])
    .slice()
    .sort((a, b) => a.floorNumber - b.floorNumber)

  const selectedNode = useMemo(
    () => (state.selectedNodeId ? (state.nodes.find((node) => node.id === state.selectedNodeId) ?? null) : null),
    [state.selectedNodeId, state.nodes],
  )

  const connectorCandidates = useMemo(
    () => deriveConnectorCandidates(navGraph, selectedNode),
    [navGraph, selectedNode],
  )

  // Handle building switch — switches building context, loads first floor
  const handleBuildingSwitch = useCallback(
    async (value: string) => {
      if (value === 'campus') {
        const campusBuilding = navGraph?.buildings.find((b) => b.name === 'Campus')
        const campusFloor = campusBuilding?.floors[0]
        switchToCampus(campusFloor?.nodes ?? [], campusFloor?.edges ?? [])
        setFloorPlanUrl('/api/campus/image')
      } else {
        const buildingId = Number(value)
        dispatch({ type: 'SWITCH_BUILDING', buildingId })
        const building = navGraph?.buildings.find((b) => b.id === buildingId)
        const firstFloor = building?.floors.slice().sort((a, b) => a.floorNumber - b.floorNumber)[0]
        if (firstFloor) {
          switchFloor(firstFloor.id, firstFloor.nodes, firstFloor.edges)
          setFloorPlanUrl(`/api/floor-plan/${buildingId}/${firstFloor.floorNumber}?t=${firstFloor.updatedAt}`)
        }
      }
    },
    [navGraph, dispatch, switchFloor, switchToCampus],
  )

  // Keyboard shortcuts for undo/redo, escape, and delete
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.ctrlKey && e.key === 'z' && !e.shiftKey) {
        e.preventDefault()
        handleUndo()
      } else if (e.ctrlKey && (e.key === 'y' || (e.key === 'z' && e.shiftKey))) {
        e.preventDefault()
        handleRedo()
      } else if (e.key === 'Escape') {
        dispatch({ type: 'SET_PENDING_EDGE_SOURCE', id: null })
        dispatch({ type: 'SELECT_NODE', id: null })
        dispatch({ type: 'SELECT_EDGE', id: null })
        setCursorCanvasPos(null)
      } else if (e.key === 'Delete' || e.key === 'Backspace') {
        const isInputFocused = ['INPUT', 'TEXTAREA', 'SELECT'].includes(
          (document.activeElement as HTMLElement)?.tagName ?? '',
        )
        if (isInputFocused) return

        if (state.selectedNodeId) {
          dispatch({ type: 'DELETE_NODE', id: state.selectedNodeId })
          recordHistory()
        } else if (state.selectedEdgeId) {
          dispatch({ type: 'DELETE_EDGE', id: state.selectedEdgeId })
          recordHistory()
        }
      }
    }

    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [handleUndo, handleRedo, dispatch, state.selectedNodeId, state.selectedEdgeId, recordHistory])

  // Handle mouse move — track cursor position for rubber-band preview
  const handleMouseMove = useCallback(() => {
    const stage = stageRef.current
    if (!stage) return

    if (state.mode === 'add-edge' && state.pendingEdgeSourceId !== null) {
      const pos = stage.getPointerPosition()
      if (!pos) return

      const stagePosition = stage.position()
      const scale = stage.scaleX()
      const canvasX = (pos.x - stagePosition.x) / scale
      const canvasY = (pos.y - stagePosition.y) / scale
      setCursorCanvasPos({ x: canvasX, y: canvasY })
    } else {
      setCursorCanvasPos(null)
    }
  }, [state.mode, state.pendingEdgeSourceId])

  // Handle stage click for node placement and selection clearing
  const handleStageClick = useCallback(
    (e: Konva.KonvaEventObject<MouseEvent>) => {
      const stage = stageRef.current
      const layer = floorPlanLayerRef.current

      if (state.mode === 'add-node') {
        // Place node on any canvas click (floor plan image is a shape, not the stage)
        // NodeMarkerLayer stops propagation for clicks on existing nodes
        if (!layer || !imageRect) return

        const pos = layer.getRelativePointerPosition()
        if (!pos) return

        const normX = Math.max(0, Math.min(1, (pos.x - imageRect.x) / imageRect.width))
        const normY = Math.max(0, Math.min(1, (pos.y - imageRect.y) / imageRect.height))

        const newNode: NavNode = {
          id: generateNodeId('room', 'New Node'),
          type: 'room',
          label: 'New Node',
          x: normX,
          y: normY,
          searchable: true,
          floorId: state.activeFloorId ?? 1,  // use active floor DB id, fallback to 1
        }

        dispatch({ type: 'PLACE_NODE', node: newNode })
        recordHistory()
        dispatch({ type: 'SELECT_NODE', id: newNode.id })
      } else if (state.mode === 'select') {
        // Clear selection when clicking empty canvas
        if (e.target === stage) {
          dispatch({ type: 'SELECT_NODE', id: null })
          dispatch({ type: 'SELECT_EDGE', id: null })
        }
      } else if (state.mode === 'add-edge') {
        // Clicking empty canvas cancels the pending edge
        if (e.target === stage) {
          dispatch({ type: 'SET_PENDING_EDGE_SOURCE', id: null })
          setCursorCanvasPos(null)
        }
      }
    },
    [state.mode, state.activeFloorId, imageRect, dispatch, recordHistory],
  )

  // Handle node click
  const handleNodeClick = useCallback(
    (nodeId: string) => {
      if (state.mode === 'select') {
        if (state.selectedNodeId === nodeId) {
          // Toggle: clicking already-selected node clears selection
          dispatch({ type: 'SELECT_NODE', id: null })
        } else {
          dispatch({ type: 'SELECT_NODE', id: nodeId })
        }
      } else if (state.mode === 'add-edge') {
        if (state.pendingEdgeSourceId === null) {
          // First click: set pending source
          dispatch({ type: 'SET_PENDING_EDGE_SOURCE', id: nodeId })
        } else if (state.pendingEdgeSourceId !== nodeId) {
          // Second click: create edge between source and target
          const sourceId = state.pendingEdgeSourceId
          const targetId = nodeId
          const source = state.nodes.find((n) => n.id === sourceId)
          const target = state.nodes.find((n) => n.id === targetId)

          if (source && target) {
            const dist = calcDistance(source, target)
            const newEdge: NavEdge = {
              id: generateEdgeId(sourceId, targetId),
              sourceId,
              targetId,
              standardWeight: dist,
              accessibleWeight: dist,
              accessible: true,
              bidirectional: true,
            }
            dispatch({ type: 'CREATE_EDGE', edge: newEdge })
            recordHistory()
            dispatch({ type: 'SELECT_EDGE', id: newEdge.id })
            setCursorCanvasPos(null)
          }
        }
        // Same node clicked: ignore (no self-loops)
      }
    },
    [state.mode, state.selectedNodeId, state.pendingEdgeSourceId, state.nodes, dispatch, recordHistory],
  )

  // Handle edge click
  const handleEdgeClick = useCallback(
    (edgeId: string) => {
      dispatch({ type: 'SELECT_EDGE', id: edgeId })
    },
    [dispatch],
  )

  // Handle node drag end — normalize position and record history
  const handleNodeDragEnd = useCallback(
    (nodeId: string, normX: number, normY: number) => {
      dispatch({ type: 'MOVE_NODE', id: nodeId, x: normX, y: normY })
      recordHistory()
    },
    [dispatch, recordHistory],
  )

  // Handle connector link/unlink updates via the atomic server endpoint
  const handleConnectorLinkChange = useCallback(
    async (direction: ConnectorDirection, targetNodeId: string | null) => {
      if (!selectedNode || !isConnectorNodeType(selectedNode.type)) return

      setConnectorLinkError(null)
      setIsConnectorLinkPending(true)

      try {
        const response = await fetch('/api/admin/connectors/link', {
          method: 'POST',
          credentials: 'include',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            sourceNodeId: selectedNode.id,
            direction,
            targetNodeId,
          }),
        })

        const payload =
          (await response.json().catch(() => ({}))) as
            | ConnectorLinkSuccessResponse
            | ConnectorLinkErrorResponse

        if (!response.ok) {
          const errorCode =
            typeof payload.errorCode === 'string' ? payload.errorCode : 'CONNECTOR_LINK_ERROR'
          const errorMessage =
            typeof payload.error === 'string' ? payload.error : 'Failed to update connector link'
          setConnectorLinkError(`${errorCode}: ${errorMessage}`)
          return
        }

        if (!('ok' in payload) || payload.ok !== true || !Array.isArray(payload.updatedNodes)) {
          setConnectorLinkError('INVALID_RESPONSE: Connector update response was malformed')
          return
        }

        const successPayload = payload as ConnectorLinkSuccessResponse

        setNavGraph((previousGraph) =>
          applyConnectorUpdatesToNavGraph(previousGraph, successPayload.updatedNodes),
        )

        const patchedActiveFloorNodes = applyConnectorUpdatesToFloorNodes(
          state.nodes,
          successPayload.updatedNodes,
        )
        if (patchedActiveFloorNodes !== state.nodes) {
          dispatch({
            type: 'REPLACE_NODES',
            nodes: patchedActiveFloorNodes,
            isDirty: state.isDirty,
          })
        }
      } catch {
        setConnectorLinkError('NETWORK_ERROR: Unable to update floor connector link')
      } finally {
        setIsConnectorLinkPending(false)
      }
    },
    [dispatch, selectedNode, state.isDirty, state.nodes],
  )

  // Handle save — POST graph to server, context-aware (campus vs floor)
  const handleSave = useCallback(async () => {
    if (isCampusActive) {
      // Campus save: find campus building/floor in navGraph
      const campusBuilding = navGraph?.buildings.find((b) => b.name === 'Campus')
      if (!campusBuilding) return
      const campusFloor = campusBuilding.floors[0]
      if (!campusFloor) return
      const graph: NavGraph = {
        buildings: [{
          ...campusBuilding,
          floors: [{ ...campusFloor, nodes: state.nodes, edges: state.edges }],
        }],
      }
      const res = await fetch('/api/admin/graph', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(graph),
      })
      if (res.ok) {
        dispatch({ type: 'MARK_SAVED' })
        setNavGraph({ buildings: navGraph!.buildings.map((b) => b.name === 'Campus' ? { ...b, floors: [{ ...campusFloor, nodes: state.nodes, edges: state.edges }] } : b) })
      }
    } else {
      // Building/floor save: wrap active floor nodes into the full NavGraph
      if (!navGraph || !activeBuilding || state.activeFloorId === null) return
      const updatedBuildings = navGraph.buildings.map((b) => {
        if (b.id !== activeBuilding.id) return b
        return {
          ...b,
          floors: b.floors.map((f) => {
            if (f.id !== state.activeFloorId) return f
            return { ...f, nodes: state.nodes, edges: state.edges }
          }),
        }
      })
      const graph: NavGraph = { buildings: updatedBuildings }
      const res = await fetch('/api/admin/graph', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(graph),
      })
      if (res.ok) {
        dispatch({ type: 'MARK_SAVED' })
        setNavGraph({ buildings: updatedBuildings })
      }
    }
  }, [isCampusActive, navGraph, activeBuilding, state.activeFloorId, state.nodes, state.edges, dispatch])

  // Handle floor switch — auto-saves current floor, loads new floor
  const handleFloorSwitch = useCallback(
    async (floor: NavFloor) => {
      if (floor.id === state.activeFloorId) return
      // Auto-save current floor silently (fire-and-forget)
      if (state.isDirty && !isCampusActive && state.activeFloorId !== null) {
        setIsSavingFloor(true)
        try {
          await handleSave()
        } catch {
          /* silent */
        } finally {
          setIsSavingFloor(false)
        }
      }
      // Switch floor
      switchFloor(floor.id, floor.nodes, floor.edges)
      setFloorPlanUrl(`/api/floor-plan/${state.activeBuildingId}/${floor.floorNumber}?t=${floor.updatedAt}`)
    },
    [state.activeFloorId, state.isDirty, state.activeBuildingId, isCampusActive, switchFloor, handleSave],
  )

  // Handle upload button click — open file picker
  const handleUploadClick = useCallback(() => {
    fileInputRef.current?.click()
  }, [])

  // Handle file selection — instant preview + background upload, routes to correct endpoint
  const handleFileChange = useCallback(
    async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0]
      if (!file) return

      // Instant local preview
      const previewUrl = URL.createObjectURL(file)
      setFloorPlanUrl(previewUrl)

      const formData = new FormData()
      formData.append('image', file)

      if (isCampusActive) {
        await fetch('/api/admin/campus/image', {
          method: 'POST',
          credentials: 'include',
          body: formData,
        })
        // Reload navGraph to pick up new campus building/floor ids
        await loadNavGraph()
      } else {
        // Per-floor upload — use active building/floor numbers
        const floorNumber =
          activeBuilding?.floors.find((f) => f.id === state.activeFloorId)?.floorNumber ?? 1
        await fetch(`/api/admin/floor-plan/${state.activeBuildingId}/${floorNumber}`, {
          method: 'POST',
          credentials: 'include',
          body: formData,
        })
      }
    },
    [isCampusActive, activeBuilding, state.activeBuildingId, state.activeFloorId, loadNavGraph],
  )

  // Compute selected edge with source/target names for side panel
  const selectedEdgeWithNames = (() => {
    if (!state.selectedEdgeId) return null
    const edge = state.edges.find((e) => e.id === state.selectedEdgeId)
    if (!edge) return null
    const sourceNode = state.nodes.find((n) => n.id === edge.sourceId)
    const targetNode = state.nodes.find((n) => n.id === edge.targetId)
    return {
      ...edge,
      sourceName: sourceNode?.label ?? edge.sourceId,
      targetName: targetNode?.label ?? edge.targetId,
    }
  })()

  return (
    <div className="relative flex h-full w-full flex-col min-h-0">
      {/* Toolbar — only shown on Map tab */}
      <div className={activeTab !== 'map' ? 'hidden' : ''}>
        <EditorToolbar
          mode={state.mode}
          onModeChange={(m) => dispatch({ type: 'SET_MODE', mode: m })}
          onUpload={handleUploadClick}
          onSave={handleSave}
          onUndo={handleUndo}
          onRedo={handleRedo}
          canUndo={canUndo}
          canRedo={canRedo}
          isDirty={state.isDirty}
          onLogout={onLogout}
          isCampusActive={isCampusActive}
          onManageFloors={() => setManageFloorsOpen(true)}
        />
      </div>

      {/* Tab bar — always visible */}
      <div className="flex gap-2 border-b border-gray-200 bg-white px-4 py-2">
        <button
          type="button"
          onClick={() => setActiveTab('map')}
          className={`rounded px-4 py-1.5 text-sm font-medium ${activeTab === 'map' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
        >
          Map
        </button>
        <button
          type="button"
          onClick={() => setActiveTab('data')}
          className={`rounded px-4 py-1.5 text-sm font-medium ${activeTab === 'data' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
        >
          Data
        </button>
      </div>

      {/* Building selector + floor tab row — only shown on Map tab */}
      {activeTab === 'map' && (
        <div className="flex items-center gap-2 border-b border-gray-200 bg-white px-4 py-1.5 flex-wrap">
          {/* Building / Campus selector */}
          <select
            value={isCampusActive ? 'campus' : String(state.activeBuildingId)}
            onChange={(e) => handleBuildingSwitch(e.target.value)}
            className="border rounded px-2 py-1 text-sm focus:outline-none focus:ring-1 focus:ring-blue-500"
          >
            <option value="campus">Campus</option>
            {nonCampusBuildings.map((b) => (
              <option key={b.id} value={String(b.id)}>{b.name}</option>
            ))}
          </select>

          {/* Floor tabs — only when a real building is active */}
          {!isCampusActive && sortedFloors.map((floor) => (
            <button
              key={floor.id}
              type="button"
              onClick={() => handleFloorSwitch(floor)}
              disabled={isSavingFloor}
              className={`px-3 py-1 rounded text-sm font-medium ${
                state.activeFloorId === floor.id
                  ? 'bg-blue-600 text-white'
                  : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
              }`}
            >
              Floor {floor.floorNumber}
            </button>
          ))}
        </div>
      )}

      {/* Map panel — mounted but hidden when Data tab is active */}
      <div
        ref={canvasContainerRef}
        className={activeTab !== 'map' ? 'hidden' : 'relative flex-1 overflow-hidden'}
      >
        <Stage
          ref={stageRef}
          width={canvasWidth}
          height={canvasHeight}
          draggable={state.mode === 'select'}
          onClick={handleStageClick}
          onMouseMove={handleMouseMove}
          onWheel={handleWheel}
          onTouchMove={handleTouchMove}
          onTouchEnd={handleTouchEnd}
          onDragEnd={handleDragEnd}
          style={{ cursor: state.mode === 'select' ? 'default' : 'crosshair' }}
        >
          {/* Layer 1: Floor plan image */}
          <Layer ref={floorPlanLayerRef}>
            {image && (
              <FloorPlanImage
                image={image}
                isFullLoaded={isFullLoaded}
                viewportWidth={canvasWidth}
                viewportHeight={canvasHeight}
                onImageRectChange={setImageRect}
                onClick={() => {
                  if (state.mode === 'select') {
                    dispatch({ type: 'SELECT_NODE', id: null })
                    dispatch({ type: 'SELECT_EDGE', id: null })
                  }
                }}
              />
            )}
          </Layer>

          {/* Layer 2: Edges (between floor plan and nodes so nodes render on top) */}
          <EdgeLayer
            edges={state.edges}
            nodes={state.nodes}
            selectedEdgeId={state.selectedEdgeId}
            pendingEdgeSourceId={state.pendingEdgeSourceId}
            cursorPosition={cursorCanvasPos}
            imageRect={imageRect}
            mode={state.mode}
            onEdgeClick={handleEdgeClick}
          />

          {/* Layer 3: Node markers */}
          <NodeMarkerLayer
            nodes={state.nodes}
            selectedNodeId={state.selectedNodeId}
            stageScale={stageScale}
            imageRect={imageRect}
            mode={state.mode}
            onNodeClick={handleNodeClick}
            onNodeDragEnd={handleNodeDragEnd}
            isCampusActive={isCampusActive}
          />
        </Stage>

        {/* Campus empty state overlay */}
        {isCampusActive && !image && (
          <div
            className="absolute inset-0 flex items-center justify-center pointer-events-auto cursor-pointer"
            onClick={handleUploadClick}
          >
            <div className="text-center text-slate-500 hover:text-slate-700">
              <p className="text-lg font-medium">Upload campus map to begin</p>
              <p className="text-sm">Click to upload an overhead image</p>
            </div>
          </div>
        )}

        {/* Side panel — HTML overlay inside the padded container (positioned relative to editor area) */}
        <div className="pointer-events-none absolute right-0 top-0 h-full">
          <div className="pointer-events-auto h-full">
            <EditorSidePanel
              selectedNode={selectedNode}
              selectedEdge={selectedEdgeWithNames}
              onUpdateNode={(id, changes) => {
                dispatch({ type: 'UPDATE_NODE', id, changes })
                recordHistory()
              }}
              onUpdateEdge={(id, changes) => {
                dispatch({ type: 'UPDATE_EDGE', id, changes })
                recordHistory()
              }}
              onDeleteNode={(id) => {
                dispatch({ type: 'DELETE_NODE', id })
                recordHistory()
              }}
              onDeleteEdge={(id) => {
                dispatch({ type: 'DELETE_EDGE', id })
                recordHistory()
              }}
              onClose={() => {
                dispatch({ type: 'SELECT_NODE', id: null })
                dispatch({ type: 'SELECT_EDGE', id: null })
              }}
              isCampusActive={isCampusActive}
              buildings={nonCampusBuildings}
              connectorCandidates={connectorCandidates}
              onConnectorLinkChange={handleConnectorLinkChange}
              connectorLinkError={connectorLinkError}
              isConnectorLinkPending={isConnectorLinkPending}
            />
          </div>
        </div>
      </div>

      {/* Data panel — mounted but hidden when Map tab is active */}
      <div className={activeTab !== 'data' ? 'hidden' : 'flex-1 overflow-auto'}>
        <DataTabToolbar
          nodes={state.nodes}
          edges={state.edges}
          activeSubTab={activeSubTab}
          onSubTabChange={setActiveSubTab}
          onImportGraph={(nodes, edges) => {
            dispatch({ type: 'LOAD_GRAPH', nodes, edges })
            recordHistory()
          }}
        />
        {activeSubTab === 'nodes' ? (
          <NodeDataTable
            nodes={state.nodes}
            selectedNodeId={state.selectedNodeId}
            onUpdateNode={(id, updates) => {
              dispatch({ type: 'UPDATE_NODE', id, changes: updates })
              recordHistory()
            }}
            onDeleteNode={(id) => {
              dispatch({ type: 'DELETE_NODE', id })
              recordHistory()
            }}
            onSelectNode={(id) => dispatch({ type: 'SELECT_NODE', id })}
          />
        ) : (
          <EdgeDataTable
            edges={state.edges}
            nodes={state.nodes}
            selectedEdgeId={state.selectedEdgeId}
            onUpdateEdge={(id, updates) => {
              dispatch({ type: 'UPDATE_EDGE', id, changes: updates })
              recordHistory()
            }}
            onDeleteEdge={(id) => {
              dispatch({ type: 'DELETE_EDGE', id })
              recordHistory()
            }}
            onSelectEdge={(id) => dispatch({ type: 'SELECT_EDGE', id })}
            recordHistory={recordHistory}
          />
        )}
      </div>

      {/* Hidden file input for floor plan upload */}
      <input
        ref={fileInputRef}
        type="file"
        accept="image/*"
        className="hidden"
        onChange={handleFileChange}
      />

      {/* Manage Floors modal */}
      {manageFloorsOpen && activeBuilding && (
        <ManageFloorsModal
          isOpen={manageFloorsOpen}
          buildingId={activeBuilding.id}
          floors={activeBuilding.floors}
          onClose={() => setManageFloorsOpen(false)}
          onFloorAdded={(newFloor) => {
            setManageFloorsOpen(false)
            setNavGraph((prev) => {
              if (!prev || !activeBuilding) return prev
              return {
                buildings: prev.buildings.map((b) =>
                  b.id === activeBuilding.id ? { ...b, floors: [...b.floors, newFloor] } : b,
                ),
              }
            })
          }}
          onFloorDeleted={(floorId) => {
            setManageFloorsOpen(false)
            setNavGraph((prev) => {
              if (!prev || !activeBuilding) return prev
              return {
                buildings: prev.buildings.map((b) =>
                  b.id === activeBuilding.id
                    ? { ...b, floors: b.floors.filter((f) => f.id !== floorId) }
                    : b,
                ),
              }
            })
          }}
          onFloorImageReplaced={() => { loadNavGraph() }}
        />
      )}
    </div>
  )
}

import type { NavEdge, NavNode } from '@shared/types'
import { renderToStaticMarkup } from 'react-dom/server'
import { describe, expect, it, vi } from 'vitest'
import EditorSidePanel from './EditorSidePanel'

function makeNode(overrides: Partial<NavNode> & { id: string; floorId: number }): NavNode {
  return {
    id: overrides.id,
    floorId: overrides.floorId,
    x: 0.4,
    y: 0.6,
    label: overrides.label ?? overrides.id,
    type: overrides.type ?? 'room',
    searchable: overrides.searchable ?? true,
    ...overrides,
  }
}

function makeEdge(): NavEdge & { sourceName: string; targetName: string } {
  return {
    id: 'edge-1',
    sourceId: 'a',
    targetId: 'b',
    sourceName: 'A',
    targetName: 'B',
    standardWeight: 1,
    accessibleWeight: 1,
    accessible: true,
    bidirectional: true,
  }
}

const noop = () => {}

describe('EditorSidePanel connector controls', () => {
  it('renders floor connection dropdowns with unlink and inline connector error for connector nodes', () => {
    const connectorNode = makeNode({
      id: 'stairs-f2',
      floorId: 102,
      type: 'stairs',
      label: 'Stairs F2',
      connectsToNodeAboveId: 'ramp-f3',
    })

    const html = renderToStaticMarkup(
      <EditorSidePanel
        selectedNode={connectorNode}
        selectedEdge={null}
        onUpdateNode={noop}
        onUpdateEdge={noop}
        onDeleteNode={noop}
        onDeleteEdge={noop}
        onClose={noop}
        isCampusActive={false}
        connectorCandidates={{
          above: [
            {
              nodeId: 'ramp-f3',
              floorId: 103,
              floorNumber: 3,
              buildingId: 1,
              buildingName: 'Science',
              label: 'Upper Ramp',
              nodeType: 'ramp',
            },
          ],
          below: [
            {
              nodeId: 'elevator-f1',
              floorId: 101,
              floorNumber: 1,
              buildingId: 1,
              buildingName: 'Science',
              label: 'Lower Elevator',
              nodeType: 'elevator',
            },
          ],
        }}
        onConnectorLinkChange={vi.fn()}
        connectorLinkError="LINK_VALIDATION_ERROR: Direction mismatch"
        isConnectorLinkPending={false}
      />,
    )

    expect(html).toContain('Floor Connections')
    expect(html).toContain('Above')
    expect(html).toContain('Below')
    expect(html).toContain('Unlink')
    expect(html).toContain('Floor 3')
    expect(html).toContain('Upper Ramp')
    expect(html).toContain('LINK_VALIDATION_ERROR: Direction mismatch')
  })

  it('does not render floor connection controls for non-connector nodes', () => {
    const roomNode = makeNode({ id: 'room-101', floorId: 101, type: 'room', label: 'Room 101' })

    const html = renderToStaticMarkup(
      <EditorSidePanel
        selectedNode={roomNode}
        selectedEdge={null}
        onUpdateNode={noop}
        onUpdateEdge={noop}
        onDeleteNode={noop}
        onDeleteEdge={noop}
        onClose={noop}
        connectorCandidates={{ above: [], below: [] }}
        onConnectorLinkChange={vi.fn()}
      />,
    )

    expect(html).not.toContain('Floor Connections')
    expect(html).not.toContain('connector-above')
    expect(html).not.toContain('connector-below')
  })

  it('keeps edge editing mode unchanged when only an edge is selected', () => {
    const html = renderToStaticMarkup(
      <EditorSidePanel
        selectedNode={null}
        selectedEdge={makeEdge()}
        onUpdateNode={noop}
        onUpdateEdge={noop}
        onDeleteNode={noop}
        onDeleteEdge={noop}
        onClose={noop}
        connectorCandidates={{ above: [], below: [] }}
        onConnectorLinkChange={vi.fn()}
      />,
    )

    expect(html).toContain('Edge Properties')
    expect(html).not.toContain('Floor Connections')
    expect(html).toContain('Connection')
  })
})

/**
 * Core navigation graph type definitions for CampusNav.
 *
 * Two categories of types:
 *
 * 1. **ngraph.graph data types** — `NavNodeData` and `NavEdgeData` are the `.data`
 *    fields stored on ngraph.graph's Node and Link objects via
 *    `graph.addNode(id, data)` and `graph.addLink(from, to, data)`.
 *
 * 2. **Serialization types** — `NavNode`, `NavEdge`, `NavFloor`, `NavBuilding`,
 *    and `NavGraph` are the JSON shapes used for API transport (GET /api/map) and
 *    file storage. The client loads a `NavGraph`, iterates `buildings[].floors[]`,
 *    destructures each node/edge into `(id, data)`, and feeds them into ngraph.graph.
 *    `NavNode` objects live inside `NavFloor.nodes[]`.
 *
 * All coordinates are **NORMALIZED** (0.0–1.0), representing percentages of the
 * floor plan image dimensions. Convert to pixels only at render time:
 * `pixelX = node.x * canvasWidth`.
 */

// ============================================================
// Node Types
// ============================================================

/**
 * Classification of navigation nodes on a floor plan.
 *
 * **Visible to students** (searchable destinations):
 * - `room` — Classroom, office, lab
 * - `entrance` — Building entrance/exit
 * - `elevator` — Elevator (also an accessibility waypoint)
 * - `restroom` — Restroom
 * - `landmark` — Named point of interest (cafeteria, library)
 *
 * **Invisible to students** (routing infrastructure only):
 * - `stairs` — Stairwell navigation waypoint, HIDDEN from student map (routing infrastructure only)
 * - `ramp` — Ramp navigation waypoint, HIDDEN from student map (routing infrastructure only)
 * - `junction` — Hallway intersection
 * - `hallway` — Mid-hallway point
 */
export type NavNodeType =
  | 'room'
  | 'entrance'
  | 'elevator'
  | 'stairs'
  | 'ramp'
  | 'restroom'
  | 'junction'
  | 'hallway'
  | 'landmark'

/**
 * Data stored on each graph node (the `.data` field of an ngraph.graph Node).
 *
 * Coordinates are normalized 0.0–1.0: percentage of floor plan width/height.
 */
export interface NavNodeData {
  /** Normalized x position (0.0 = left edge, 1.0 = right edge of floor plan) */
  x: number
  /** Normalized y position (0.0 = top edge, 1.0 = bottom edge of floor plan) */
  y: number
  /** Display label for search results and turn-by-turn directions */
  label: string
  /** Node classification — determines visibility and search behavior */
  type: NavNodeType
  /** Whether this node appears in student search results */
  searchable: boolean
  /** ID of the floors record this node belongs to (FK → floors.id) */
  floorId: number
  // buildingName REMOVED — derived transitively via floor → building
  /** Room/office number identifier (e.g. "204", "A-102") */
  roomNumber?: string
  /** Human-readable description shown in location detail sheet */
  description?: string
  /** Accessibility information shown in detail sheet */
  accessibilityNotes?: string
  // Floor connector linkage — only set on stairs, elevator, ramp nodes
  /** ID of the floor above that this connector node links to */
  connectsToFloorAboveId?: number
  /** ID of the floor below that this connector node links to */
  connectsToFloorBelowId?: number
  /** ID of the corresponding node on the floor above */
  connectsToNodeAboveId?: string
  /** ID of the corresponding node on the floor below */
  connectsToNodeBelowId?: string
  /** ID of the building this campus entrance marker bridges to (campus map only, entrance nodes) */
  connectsToBuildingId?: number
}

// ============================================================
// Edge Types
// ============================================================

/**
 * Data stored on each graph edge (the `.data` field of an ngraph.graph Link).
 *
 * Every edge carries **dual weights** to enable accessibility routing:
 * - `standardWeight`: cost for the standard walking route
 * - `accessibleWeight`: cost for the wheelchair-accessible route
 *   (same as standard for flat paths; higher for detours like ramps;
 *   `Infinity` for non-accessible edges like stairs)
 */
export interface NavEdgeData {
  /**
   * Walking cost for the standard route.
   * Typically the Euclidean distance between connected nodes in normalized
   * coordinates. Can be overridden by an admin for non-straight paths.
   */
  standardWeight: number
  /**
   * Walking cost for the wheelchair-accessible route.
   * - Same as `standardWeight` for accessible paths.
   * - Higher than `standardWeight` if the accessible path is longer (e.g. ramp).
   * - `Infinity` for non-accessible edges (e.g. stairs without elevator).
   */
  accessibleWeight: number
  /** Whether this edge is traversable by wheelchair */
  accessible: boolean
  /** Whether this edge can be traversed in both directions */
  bidirectional: boolean
  /** Optional admin notes ("3 steps", "narrow doorway", "automatic door") */
  accessibilityNotes?: string
}

// ============================================================
// Serialization Types (API / JSON transport)
// ============================================================

/**
 * A serialized node for JSON transport (API responses, file storage).
 * Combines the node's unique ID with its data fields.
 * NavNode inherits `floorId` from NavNodeData — no direct change needed.
 */
export interface NavNode extends NavNodeData {
  /** Unique identifier for this node (e.g. "room-204", "entrance-main") */
  id: string
}

/**
 * A serialized edge for JSON transport (API responses, file storage).
 * Combines the edge's ID, endpoint references, and data fields.
 */
export interface NavEdge extends NavEdgeData {
  /** Unique identifier for this edge */
  id: string
  /** Source node ID */
  sourceId: string
  /** Target node ID */
  targetId: string
}

/**
 * Optional real-world GPS bounds used to project normalized floor coordinates
 * onto latitude/longitude space.
 */
export interface NavFloorGpsBounds {
  /** Minimum latitude represented by this floor map */
  minLat: number
  /** Maximum latitude represented by this floor map */
  maxLat: number
  /** Minimum longitude represented by this floor map */
  minLng: number
  /** Maximum longitude represented by this floor map */
  maxLng: number
}

/**
 * A single floor within a building, containing all nodes and edges on that floor.
 */
export interface NavFloor {
  /** Database ID of this floor record (floors.id) */
  id: number
  /** Floor number (1-based) */
  floorNumber: number
  /** Path to the floor plan image asset */
  imagePath: string
  /** ISO 8601 timestamp of last graph modification */
  updatedAt: string
  /** Optional GPS calibration bounds for this floor */
  gpsBounds?: NavFloorGpsBounds
  /** All navigation nodes on this floor */
  nodes: NavNode[]
  /** All navigation edges on this floor */
  edges: NavEdge[]
}

/**
 * A building containing one or more floors.
 */
export interface NavBuilding {
  /** Database ID of this building record (buildings.id) */
  id: number
  /** Display name of the building */
  name: string
  /** All floors within this building */
  floors: NavFloor[]
}

/**
 * Complete navigation graph as JSON — returned by `GET /api/map`.
 *
 * The client loads this on page init and builds an ngraph.graph instance
 * by iterating the nested buildings → floors → nodes/edges structure:
 * ```ts
 * const graph = createGraph<NavNodeData, NavEdgeData>()
 * for (const building of navGraph.buildings) {
 *   for (const floor of building.floors) {
 *     for (const { id, ...data } of floor.nodes) graph.addNode(id, data)
 *     for (const { id, sourceId, targetId, ...data } of floor.edges)
 *       graph.addLink(sourceId, targetId, data)
 *   }
 * }
 * ```
 */
export interface NavGraph {
  /** All buildings in the campus, each containing floors with nodes and edges */
  buildings: NavBuilding[]
  // nodes and edges now live under buildings[].floors[].nodes/edges
  // metadata replaced by floors[].updatedAt
}

import type { NavFloorGpsBounds } from '@shared/types'
import { eq } from 'drizzle-orm'
import { db } from './db/client'
import { floors } from './db/schema'

export interface FloorGpsBoundsColumns {
  gpsMinLat: number | null
  gpsMaxLat: number | null
  gpsMinLng: number | null
  gpsMaxLng: number | null
}

export type FloorGpsBoundsErrorCode =
  | 'INVALID_REQUEST'
  | 'GPS_BOUNDS_INCOMPLETE'
  | 'BOUNDS_RANGE_INVALID'
  | 'FLOOR_NOT_FOUND'

type FloorGpsBoundsErrorStatus = 400 | 404

const FLOOR_GPS_BOUNDS_ERROR_STATUS = {
  INVALID_REQUEST: 400,
  GPS_BOUNDS_INCOMPLETE: 400,
  BOUNDS_RANGE_INVALID: 400,
  FLOOR_NOT_FOUND: 404,
} as const satisfies Record<FloorGpsBoundsErrorCode, FloorGpsBoundsErrorStatus>

export class FloorGpsBoundsError extends Error {
  readonly code: FloorGpsBoundsErrorCode
  readonly status: FloorGpsBoundsErrorStatus

  constructor(code: FloorGpsBoundsErrorCode, message: string) {
    super(message)
    this.name = 'FloorGpsBoundsError'
    this.code = code
    this.status = FLOOR_GPS_BOUNDS_ERROR_STATUS[code]
  }
}

export interface FloorGpsBoundsUpdateResult {
  ok: true
  floorId: number
  gpsBounds: NavFloorGpsBounds | null
}

interface FloorGpsBoundsRow extends FloorGpsBoundsColumns {
  id: number
}

export interface FloorGpsBoundsStoreTx {
  getFloorById(floorId: number): Promise<FloorGpsBoundsRow | null>
  updateFloorGpsBounds(floorId: number, bounds: FloorGpsBoundsColumns): Promise<FloorGpsBoundsRow | null>
}

export interface FloorGpsBoundsStore {
  transaction<T>(callback: (tx: FloorGpsBoundsStoreTx) => Promise<T>): Promise<T>
}

type DrizzleFloorGpsBoundsTx = Pick<typeof db, 'select' | 'update'>

function isFiniteNumber(value: unknown): value is number {
  return typeof value === 'number' && Number.isFinite(value)
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null
}

function parseFloorGpsBoundsTuple(values: {
  minLat: unknown
  maxLat: unknown
  minLng: unknown
  maxLng: unknown
}): FloorGpsBoundsColumns {
  const { minLat, maxLat, minLng, maxLng } = values
  const tupleValues = [minLat, maxLat, minLng, maxLng] as const

  if (tupleValues.some(value => value === undefined)) {
    throw new FloorGpsBoundsError(
      'GPS_BOUNDS_INCOMPLETE',
      'minLat, maxLat, minLng, and maxLng must all be provided',
    )
  }

  if (tupleValues.every(value => value === null)) {
    return {
      gpsMinLat: null,
      gpsMaxLat: null,
      gpsMinLng: null,
      gpsMaxLng: null,
    }
  }

  if (tupleValues.some(value => value === null)) {
    throw new FloorGpsBoundsError(
      'GPS_BOUNDS_INCOMPLETE',
      'GPS bounds must be a complete numeric tuple or a full null clear tuple',
    )
  }

  if (
    !isFiniteNumber(minLat)
    || !isFiniteNumber(maxLat)
    || !isFiniteNumber(minLng)
    || !isFiniteNumber(maxLng)
  ) {
    throw new FloorGpsBoundsError(
      'INVALID_REQUEST',
      'minLat, maxLat, minLng, and maxLng must be finite numbers or all null',
    )
  }

  if (minLat >= maxLat || minLng >= maxLng) {
    throw new FloorGpsBoundsError(
      'BOUNDS_RANGE_INVALID',
      'GPS bounds must satisfy minLat < maxLat and minLng < maxLng',
    )
  }

  return {
    gpsMinLat: minLat,
    gpsMaxLat: maxLat,
    gpsMinLng: minLng,
    gpsMaxLng: maxLng,
  }
}

/**
 * Converts nullable DB floor GPS columns into a complete GPS bounds object.
 * Returns null when any value is missing (or non-finite), ensuring callers never
 * serialize partial coordinate tuples.
 */
export function toNavFloorGpsBounds(row: FloorGpsBoundsColumns): NavFloorGpsBounds | null {
  if (
    !isFiniteNumber(row.gpsMinLat)
    || !isFiniteNumber(row.gpsMaxLat)
    || !isFiniteNumber(row.gpsMinLng)
    || !isFiniteNumber(row.gpsMaxLng)
  ) {
    return null
  }

  return {
    minLat: row.gpsMinLat,
    maxLat: row.gpsMaxLat,
    minLng: row.gpsMinLng,
    maxLng: row.gpsMaxLng,
  }
}

export function serializeFloorGpsBounds(row: FloorGpsBoundsColumns): { gpsBounds?: NavFloorGpsBounds } {
  const gpsBounds = toNavFloorGpsBounds(row)
  return gpsBounds ? { gpsBounds } : {}
}

export function parseFloorGpsBoundsUpdatePayload(payload: unknown): FloorGpsBoundsColumns {
  if (!isRecord(payload)) {
    throw new FloorGpsBoundsError('INVALID_REQUEST', 'Request body must be a JSON object')
  }

  return parseFloorGpsBoundsTuple({
    minLat: payload.minLat,
    maxLat: payload.maxLat,
    minLng: payload.minLng,
    maxLng: payload.maxLng,
  })
}

function createDrizzleStoreTx(tx: DrizzleFloorGpsBoundsTx): FloorGpsBoundsStoreTx {
  return {
    async getFloorById(floorId) {
      const [row] = await tx
        .select({
          id: floors.id,
          gpsMinLat: floors.gpsMinLat,
          gpsMaxLat: floors.gpsMaxLat,
          gpsMinLng: floors.gpsMinLng,
          gpsMaxLng: floors.gpsMaxLng,
        })
        .from(floors)
        .where(eq(floors.id, floorId))
        .limit(1)

      return row ?? null
    },

    async updateFloorGpsBounds(floorId, bounds) {
      const [row] = await tx
        .update(floors)
        .set({
          ...bounds,
          updatedAt: new Date().toISOString(),
        })
        .where(eq(floors.id, floorId))
        .returning({
          id: floors.id,
          gpsMinLat: floors.gpsMinLat,
          gpsMaxLat: floors.gpsMaxLat,
          gpsMinLng: floors.gpsMinLng,
          gpsMaxLng: floors.gpsMaxLng,
        })

      return row ?? null
    },
  }
}

const drizzleFloorGpsBoundsStore: FloorGpsBoundsStore = {
  transaction(callback) {
    return db.transaction(async (tx) => callback(createDrizzleStoreTx(tx)))
  },
}

async function executeUpdateFloorGpsBounds(
  tx: FloorGpsBoundsStoreTx,
  floorId: number,
  bounds: FloorGpsBoundsColumns,
): Promise<FloorGpsBoundsUpdateResult> {
  const existingFloor = await tx.getFloorById(floorId)
  if (!existingFloor) {
    throw new FloorGpsBoundsError('FLOOR_NOT_FOUND', `Floor ${floorId} was not found`)
  }

  const updatedFloor = await tx.updateFloorGpsBounds(existingFloor.id, bounds)
  if (!updatedFloor) {
    throw new FloorGpsBoundsError('FLOOR_NOT_FOUND', `Floor ${floorId} was not found`)
  }

  return {
    ok: true,
    floorId: updatedFloor.id,
    gpsBounds: toNavFloorGpsBounds(updatedFloor),
  }
}

export async function updateFloorGpsBounds(
  floorId: number,
  bounds: FloorGpsBoundsColumns,
  options?: { store?: FloorGpsBoundsStore },
): Promise<FloorGpsBoundsUpdateResult> {
  if (!Number.isInteger(floorId) || floorId <= 0) {
    throw new FloorGpsBoundsError('INVALID_REQUEST', 'floorId must be a positive integer')
  }

  const store = options?.store ?? drizzleFloorGpsBoundsStore
  return store.transaction(async (tx) => executeUpdateFloorGpsBounds(tx, floorId, bounds))
}

export async function updateFloorGpsBoundsFromPayload(
  floorId: number,
  payload: unknown,
  options?: { store?: FloorGpsBoundsStore },
): Promise<FloorGpsBoundsUpdateResult> {
  const bounds = parseFloorGpsBoundsUpdatePayload(payload)
  return updateFloorGpsBounds(floorId, bounds, options)
}

