        selectedEdgeId: null,
        pendingEdgeSourceId: null,
      }

    case 'SET_MODE':
      return {
        ...state,
        mode: action.mode,
        selectedNodeId: null,
        selectedEdgeId: null,
        pendingEdgeSourceId: null,
      }

    case 'PLACE_NODE':
      return {
        ...state,
        nodes: [...state.nodes, action.node],
        isDirty: true,
      }

    case 'MOVE_NODE':
      return {
        ...state,
        nodes: state.nodes.map((n) =>
          n.id === action.id ? { ...n, x: action.x, y: action.y } : n,
        ),
